# Board.py

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        piece_types = ['R', 'N', 'B', 'Q', 'K', 'B', 'N', 'R']
        player_1_row, player_2_row = 0, 7
        for i in range(8):
            for j in range(8):
                if (i + j) % 2 == 1:
                    if i < 3:
                        self.board[i][j] = Piece(piece_types[j], True)
                    elif i > 4:
                        self.board[i][j] = Piece(piece_types[j], False)

    def display(self):
        print("     A B C D E F G H")
        for i in range(8):
            print(f"{i + 1} |", end=" ")
            for j in range(8):
                if self.board[i][j]:
                    print(self.board[i][j].symbol, end="| ")
                else:
                    print("  | ", end="")
            print(f"\n   -----------------")

    def move_piece(self, start, end):
        x1, y1 = start
        x2, y2 = end
        if self.board[x1][y1]:
            piece = self.board[x1][y1]
            self.board[x1][y1] = None
            self.board[x2][y2] = piece
            if (x2 == 0 and piece.color) or (x2 == 7 and not piece.color):
                piece.king()
